package com.hospital.management.controller.medical;import com.hospital.management.model.*;import com.hospital.management.service.*;import com.hospital.management.service.impl.*;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.IOException;
@WebServlet("/medical-records/create")public class MedicalRecordCreateServlet extends HttpServlet {private final MedicalRecordService service;private final AppointmentService appointments;public MedicalRecordCreateServlet(){this(new MedicalRecordServiceImpl(),new AppointmentServiceImpl());}public MedicalRecordCreateServlet(MedicalRecordService s,AppointmentService a){service=s;appointments=a;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{Long id=MedicalRequest.id(q.getParameter("appointmentId"));if(id==null){r.sendError(400);return;}if(service.getRecordByAppointment(id,MedicalRequest.user(q)).isPresent()){r.sendRedirect(q.getContextPath()+"/medical-records/view?appointmentId="+id);return;}MedicalRecordForm f=new MedicalRecordForm();f.setAppointmentId(id);show(q,r,f);}protected void doPost(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{MedicalRecordForm f=MedicalRequest.form(q);ServiceResult<Long>x=service.createRecord(f,MedicalRequest.audit(q),MedicalRequest.user(q));if(x.isSuccess()){r.sendRedirect(q.getContextPath()+"/medical-records/view?id="+x.getData());return;}q.setAttribute("errors",x.getErrors());q.setAttribute("errorMessage",x.getMessage());show(q,r,f);}private void show(HttpServletRequest q,HttpServletResponse r,MedicalRecordForm f)throws ServletException,IOException{Appointment a=f.getAppointmentId()==null?null:appointments.getAppointment(f.getAppointmentId(),MedicalRequest.user(q)).orElse(null);if(a==null){r.sendError(404);return;}q.setAttribute("appointment",a);q.setAttribute("recordForm",f);q.setAttribute("formMode","CREATE");q.getRequestDispatcher("/WEB-INF/views/medical-records/form.jsp").forward(q,r);}}
